describe('SHMS API — Alertas ICOLD', () => {
  it('deve classificar alertas corretamente por nível', () => {
    // ICOLD Bulletin 158 §4.3: L1 < L2 < L3 (crescente severidade)
    const classifyAlert = (value: number, thresholds: { l1: number; l2: number; l3: number }) => {
      if (value >= thresholds.l3) return 'L3';
      if (value >= thresholds.l2) return 'L2';
      if (value >= thresholds.l1) return 'L1';
      return 'NORMAL';
    };
    
    const thresholds = { l1: 1.0, l2: 2.0, l3: 3.0 };
    
    expect(classifyAlert(0.5, thresholds)).toBe('NORMAL');
    expect(classifyAlert(1.5, thresholds)).toBe('L1');
    expect(classifyAlert(2.5, thresholds)).toBe('L2');
    expect(classifyAlert(3.5, thresholds)).toBe('L3');
  });
});
